          background: var(--surface);
          border-radius: 24px;
          padding: 38px 36px;
          box-shadow: var(--shadow-lg);
        }
        .form-title {
          font-family: 'Cormorant Garamond', serif;
          font-size: 1.6rem;
          font-weight: 700;
          color: var(--text);
          margin-bottom: 6px;
        }
        .form-sub { font-family: 'Outfit', sans-serif; font-size: 0.88rem; color: var(--muted); margin-bottom: 28px; }
        .form-group { margin-bottom: 18px; }
        .form-group label {
          display: block;
          font-family: 'Outfit', sans-serif;
          font-size: 0.82rem;
          font-weight: 600;
          color: var(--text2);
          margin-bottom: 7px;
          letter-spacing: 0.03em;
        }
        .form-group input,
        .form-group select,
        .form-group textarea {
          width: 100%;
          border: 1.5px solid var(--border);
          border-radius: 12px;
          padding: 12px 16px;
          font-family: 'Outfit', sans-serif;
          font-size: 0.93rem;
          color: var(--text);
          background: var(--bg);
          transition: border-color 0.2s, box-shadow 0.2s;
          outline: none;
          appearance: none;
        }
        .form-group input:focus,
        .form-group select:focus,
        .form-group textarea:focus {
          border-color: var(--sage);
          box-shadow: 0 0 0 4px rgba(61,107,79,0.1);
        }
        .form-row { display: grid; grid-template-columns: 1fr 1fr; gap: 14px; }
        .form-submit {
          width: 100%;
          background: var(--sage-l);
          color: #fff;
          border: none;
          border-radius: 50px;
          padding: 15px;
          font-family: 'Outfit', sans-serif;
          font-weight: 700;
          font-size: 1rem;
          cursor: pointer;
          margin-top: 6px;
          box-shadow: 0 6px 24px rgba(90,148,112,0.3);
          transition: background 0.2s, transform 0.2s, box-shadow 0.2s;
          letter-spacing: 0.03em;
        }
        .form-submit:hover { background: var(--sage-d); transform: translateY(-2px); box-shadow: 0 10px 32px rgba(42,78,57,0.35); }

        /* ── INFO STRIP ────────────────────────────── */
        .info-strip {
          background: var(--bg2);
          padding: 60px 40px;
          border-top: 1px solid var(--border);
          border-bottom: 1px solid var(--border);
        }
        .info-strip-inner {
          max-width: 1000px;
          margin: 0 auto;
          display: grid;
          grid-template-columns: repeat(3, 1fr);
          gap: 30px;
        }
        .info-item {
          display: flex;
          align-items: center;
          gap: 18px;
          padding: 22px 24px;
          background: var(--surface);
          border: 1px solid var(--border);
          border-radius: 18px;
          text-decoration: none;
          transition: transform 0.35s cubic-bezier(.34,1.56,.64,1), box-shadow 0.3s, border-color 0.3s;
        }
        .info-item:hover {
          transform: translateY(-6px);
          box-shadow: var(--shadow);
          border-color: rgba(61,107,79,0.28);
        }
        .info-icon-box {
          width: 48px;
          height: 48px;
          border-radius: 14px;
          display: flex;
          align-items: center;
          justify-content: center;
          font-size: 1.4rem;
          flex-shrink: 0;
        }
        .info-icon-box.green { background: var(--sage-xs); }
        .info-icon-box.gold { background: var(--gold-xs); }
        .info-text-label {
          font-family: 'Outfit', sans-serif;
          font-size: 0.72rem;
          font-weight: 700;
          text-transform: uppercase;
          letter-spacing: 0.1em;
          color: var(--muted);
          margin-bottom: 4px;
        }
        .info-text-val {
          font-family: 'Outfit', sans-serif;
          font-size: 0.95rem;
          font-weight: 600;
          color: var(--text);
        }

        /* ── TESTIMONIALS ──────────────────────────── */
        .reviews-section {
          background: var(--bg);
          padding: 100px 40px;
        }
        .reviews-inner { max-width: 1200px; margin: 0 auto; }
        .reviews-header { text-align: center; margin-bottom: 56px; }
        .reviews-header .section-sub { margin: 0 auto; }
        .reviews-grid {
          display: grid;
          grid-template-columns: repeat(3, 1fr);
          gap: 28px;
        }
        .review-card {
          background: var(--surface);
          border: 1px solid var(--border);
          border-radius: var(--radius);
          padding: 30px 28px;
          transition: transform 0.45s cubic-bezier(.34,1.56,.64,1), box-shadow 0.35s;
        }
        .review-card:hover {
          transform: translateY(-8px);
          box-shadow: 0 18px 50px rgba(61,107,79,0.12);
        }
        .review-stars { color: var(--gold); font-size: 1rem; letter-spacing: 2px; margin-bottom: 16px; }
        .review-text {
          font-family: 'Outfit', sans-serif;
          font-size: 0.93rem;
          color: var(--text2);
          line-height: 1.7;
          margin-bottom: 22px;
        }
        .review-author { display: flex; align-items: center; gap: 12px; }
        .review-avatar {
          width: 44px;
          height: 44px;
          border-radius: 50%;
          object-fit: cover;
          border: 2px solid var(--border);
        }
        .review-name {
          font-family: 'Outfit', sans-serif;
          font-size: 0.9rem;
          font-weight: 600;
          color: var(--text);
        }
        .review-pet { font-size: 0.78rem; color: var(--muted); }

        /* ── RESPONSIVE ────────────────────────────── */
        @media (max-width: 1100px) {
          .hero-inner { grid-template-columns: 1fr; gap: 50px; }
          .about-inner { grid-template-columns: 1fr; gap: 50px; }
