import React, { useEffect, useRef } from "react";

// Replace Nav import with your actual Nav component path
// import Nav from "./Nav";

function Clinic() {
  const revealRefs = useRef([]);

  useEffect(() => {
    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            entry.target.classList.add("visible");
          }
        });
      },
      { threshold: 0.13 }
    );
    revealRefs.current.forEach((el) => el && observer.observe(el));
    return () => observer.disconnect();
  }, []);

  const addReveal = (el) => {
    if (el && !revealRefs.current.includes(el)) revealRefs.current.push(el);
  };

  const services = [
    {
      icon: "🩺",
      title: "General Consultation",
      desc: "Expert health check-ups and routine examinations for all pet species — dogs, cats, birds, and fish.",
      tag: "Available Daily",
    },
    {
      icon: "💉",
      title: "Vaccination & Deworming",
      desc: "Complete immunization schedules and parasite prevention tailored for your pet's breed and age.",
      tag: "Walk-in Welcome",
    },
    {
      icon: "🔬",
      title: "Diagnostic Lab",
      desc: "In-house blood work, urinalysis, X-rays, and ultrasound for fast and accurate diagnosis.",
      tag: "Same-Day Reports",
    },
    {
      icon: "🏥",
      title: "Surgery & ICU",
      desc: "State-of-the-art surgical suite with 24/7 intensive care monitoring for critical patients.",
      tag: "24/7 Emergency",
    },
    {
      icon: "✂️",
      title: "Grooming & Spa",
      desc: "Professional grooming, dental cleaning, and spa treatments to keep your pet looking their best.",
      tag: "By Appointment",
    },
    {
      icon: "🐠",
      title: "Aquatic & Avian Care",
      desc: "Specialist care for exotic birds and aquarium fish — disease diagnosis, nutrition, and habitat advice.",
      tag: "Specialist Clinic",
    },
  ];

  const vets = [
    {
      name: "Dr. Priya Sharma",
      role: "Chief Veterinarian",
      spec: "Small Animals & Surgery",
      img: "https://images.unsplash.com/photo-1559839734-2b71ea197ec2?w=400&q=80",
      exp: "12 yrs exp.",
    },
    {
      name: "Dr. Arjun Mehta",
      role: "Senior Vet",
      spec: "Exotic Birds & Reptiles",
      img: "https://images.unsplash.com/photo-1612349317150-e413f6a5b16d?w=400&q=80",
      exp: "8 yrs exp.",
    },
    {
      name: "Dr. Sneha Patel",
      role: "Aquatic Specialist",
      spec: "Fish & Marine Life",
      img: "https://images.unsplash.com/photo-1594824476967-48c8b964273f?w=400&q=80",
      exp: "6 yrs exp.",
    },
  ];

  const stats = [
    { num: "12,000+", label: "Happy Pets Treated" },
    { num: "98%", label: "Recovery Rate" },
    { num: "24/7", label: "Emergency Care" },
    { num: "15+", label: "Years of Trust" },
  ];

  return (
    <>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Cormorant+Garamond:ital,wght@0,400;0,600;0,700;1,400;1,700&family=Outfit:wght@300;400;500;600;700&display=swap');

        :root {
          --bg:        #f4f1eb;
          --bg2:       #ede8de;
          --surface:   #ffffff;
          --card:      #faf8f4;
          --sage:      #3d6b4f;
          --sage-d:    #2a4e39;
          --sage-l:    #5a9470;
          --sage-xs:   rgba(61,107,79,0.09);
          --sage-sm:   rgba(61,107,79,0.18);
          --gold:      #b8922a;
          --gold-l:    #d4ac48;
          --gold-xs:   rgba(184,146,42,0.12);
          --border:    rgba(61,107,79,0.13);
          --border2:   rgba(184,146,42,0.18);
          --text:      #1c2b22;
          --text2:     #3a4a3f;
          --muted:     #7a907f;
          --dim:       #aab8ac;
          --ivory:     #fdf9f2;
          --shadow:    0 4px 24px rgba(30,50,35,0.08);
          --shadow-lg: 0 16px 60px rgba(30,50,35,0.14);
          --radius:    20px;
        }

        * { box-sizing: border-box; margin: 0; padding: 0; }

        body { font-family: 'Outfit', sans-serif; background: var(--bg); color: var(--text); }

        ::-webkit-scrollbar { width: 5px; }
        ::-webkit-scrollbar-thumb { background: var(--sage); border-radius: 10px; }

        @keyframes fadeUp   { from{opacity:0;transform:translateY(28px)} to{opacity:1;transform:none} }
        @keyframes slideL   { from{opacity:0;transform:translateX(-24px)} to{opacity:1;transform:none} }
        @keyframes floatY   { 0%,100%{transform:translateY(0)} 50%{transform:translateY(-12px)} }
        @keyframes orbDrift { 0%,100%{transform:translate(0,0) scale(1)} 40%{transform:translate(40px,-30px) scale(1.08)} 70%{transform:translate(-20px,20px) scale(0.96)} }
        @keyframes shimmer  { 0%{background-position:-200% center} 100%{background-position:200% center} }
        @keyframes pulse    { 0%,100%{opacity:1} 50%{opacity:0.6} }

        .reveal { opacity: 0; transform: translateY(24px); transition: opacity 0.65s ease, transform 0.65s ease; }
        .reveal.visible { opacity: 1; transform: none; }

        /* ── HERO ─────────────────────────────────── */
        .clinic-hero {
          position: relative;
          min-height: 92vh;
          background: linear-gradient(160deg, #1e3a28, #2a5a3c, #1a4030);
          display: flex;
          align-items: center;
          overflow: hidden;
        }
        .clinic-hero::before {
          content: '';
          position: absolute;
          inset: 0;
          background: url('https://images.unsplash.com/photo-1582213782179-e0d53f98f2ca?w=1600&q=80') center/cover no-repeat;
          opacity: 0.13;
        }
        .hero-orb {
          position: absolute;
          border-radius: 50%;
          filter: blur(70px);
          pointer-events: none;
          animation: orbDrift 14s ease-in-out infinite;
        }
        .hero-orb-1 { width:420px; height:420px; background:rgba(90,148,112,0.22); top:-80px; right:-60px; animation-delay:-4s; }
        .hero-orb-2 { width:280px; height:280px; background:rgba(184,146,42,0.14); bottom:60px; left:30px; animation-delay:-9s; }

        .hero-inner {
          position: relative;
          z-index: 2;
          max-width: 1200px;
          margin: 0 auto;
          padding: 80px 40px;
          display: grid;
          grid-template-columns: 1fr 1fr;
          gap: 60px;
          align-items: center;
        }
        .hero-badge {
          display: inline-flex;
          align-items: center;
          gap: 8px;
          background: rgba(255,255,255,0.1);
          border: 1px solid rgba(255,255,255,0.18);
          border-radius: 50px;
          padding: 6px 16px;
          font-family: 'Outfit', sans-serif;
          font-size: 0.72rem;
          font-weight: 600;
          letter-spacing: 0.15em;
          text-transform: uppercase;
          color: #a8d8b9;
          margin-bottom: 24px;
          animation: fadeUp 0.8s ease both;
        }
        .hero-badge .dot { width: 7px; height: 7px; border-radius: 50%; background: #3ecf8e; animation: pulse 2s infinite; }
        .hero-title {
          font-family: 'Cormorant Garamond', serif;
          font-size: clamp(2.8rem, 5vw, 4.2rem);
          font-weight: 700;
          line-height: 1.1;
          color: #fff;
          margin-bottom: 20px;
          animation: fadeUp 0.9s 0.15s ease both;
        }
        .hero-title em { color: var(--gold-l); font-style: italic; }
        .hero-desc {
          font-family: 'Outfit', sans-serif;
          font-size: 1.05rem;
          color: rgba(255,255,255,0.72);
          line-height: 1.7;
          margin-bottom: 36px;
          animation: fadeUp 1s 0.25s ease both;
        }
        .hero-actions {
          display: flex;
          gap: 16px;
          flex-wrap: wrap;
          animation: fadeUp 1s 0.35s ease both;
        }
        .btn-sage {
          background: var(--sage-l);
          color: #fff;
          border: none;
          border-radius: 50px;
          padding: 14px 32px;
          font-family: 'Outfit', sans-serif;
          font-weight: 600;
          font-size: 0.95rem;
          cursor: pointer;
          box-shadow: 0 4px 20px rgba(90,148,112,0.35);
          transition: background 0.2s, transform 0.2s, box-shadow 0.2s;
          text-decoration: none;
          display: inline-block;
        }
        .btn-sage:hover { background: var(--sage-d); transform: translateY(-2px); box-shadow: 0 8px 28px rgba(42,78,57,0.4); }
        .btn-glass {
          background: rgba(255,255,255,0.1);
          color: #fff;
          border: 1.5px solid rgba(255,255,255,0.28);
          border-radius: 50px;
          padding: 14px 32px;
          font-family: 'Outfit', sans-serif;
          font-weight: 600;
          font-size: 0.95rem;
          cursor: pointer;
          backdrop-filter: blur(8px);
          transition: background 0.2s, transform 0.2s;
          text-decoration: none;
          display: inline-block;
        }
        .btn-glass:hover { background: rgba(255,255,255,0.18); transform: translateY(-2px); }
        .btn-gold {
          background: var(--gold);
          color: #fff;
          border: none;
          border-radius: 50px;
          padding: 14px 32px;
          font-family: 'Outfit', sans-serif;
          font-weight: 600;
          font-size: 0.95rem;
          cursor: pointer;
          box-shadow: 0 4px 20px rgba(184,146,42,0.3);
          transition: background 0.2s, transform 0.2s;
          text-decoration: none;
          display: inline-block;
        }
        .btn-gold:hover { background: var(--gold-l); transform: translateY(-2px); }

        /* Hero Right — Clinic Image Card */
        .hero-img-card {
          position: relative;
          border-radius: 28px;
          overflow: hidden;
          box-shadow: var(--shadow-lg);
          animation: fadeUp 1s 0.4s ease both;
        }
        .hero-img-card img {
          width: 100%;
          height: 460px;
          object-fit: cover;
          display: block;
        }
        .hero-img-overlay {
          position: absolute;
          inset: 0;
          background: linear-gradient(to top, rgba(26,64,48,0.7) 0%, transparent 55%);
        }
        .hero-img-tag {
          position: absolute;
          bottom: 24px;
          left: 24px;
          background: rgba(255,255,255,0.12);
          backdrop-filter: blur(12px);
          border: 1px solid rgba(255,255,255,0.2);
          border-radius: 14px;
          padding: 12px 18px;
          color: #fff;
        }
        .hero-img-tag strong { display: block; font-family: 'Cormorant Garamond', serif; font-size: 1.2rem; }
        .hero-img-tag span { font-size: 0.78rem; opacity: 0.8; }
        .hero-rating-chip {
          position: absolute;
          top: 20px;
          right: 20px;
          background: var(--gold);
          color: #fff;
          border-radius: 50px;
          padding: 6px 14px;
          font-family: 'Outfit', sans-serif;
          font-size: 0.82rem;
          font-weight: 700;
        }

        /* ── STATS ─────────────────────────────────── */
        .stats-band {
          background: var(--sage-d);
          padding: 50px 40px;
        }
        .stats-grid {
          max-width: 1000px;
          margin: 0 auto;
          display: grid;
          grid-template-columns: repeat(4, 1fr);
          gap: 30px;
          text-align: center;
        }
        .stat-item {}
        .stat-num {
          font-family: 'Cormorant Garamond', serif;
          font-size: 2.8rem;
          font-weight: 700;
          color: var(--gold-l);
          line-height: 1;
          margin-bottom: 8px;
        }
        .stat-label {
          font-family: 'Outfit', sans-serif;
          font-size: 0.88rem;
          color: rgba(255,255,255,0.72);
          font-weight: 500;
          letter-spacing: 0.04em;
        }

        /* ── LABEL TAG ─────────────────────────────── */
        .label-tag {
          font-size: 0.7rem;
          font-weight: 700;
          letter-spacing: 0.2em;
          text-transform: uppercase;
          color: var(--sage);
          display: flex;
          align-items: center;
          gap: 8px;
          margin-bottom: 14px;
        }
        .label-tag::before {
          content: '';
          width: 24px;
          height: 2px;
          background: var(--sage);
          border-radius: 2px;
        }
        .label-tag-gold {
          font-size: 0.7rem;
          font-weight: 700;
          letter-spacing: 0.2em;
          text-transform: uppercase;
          color: var(--gold);
          display: flex;
          align-items: center;
          gap: 8px;
          margin-bottom: 14px;
        }
        .label-tag-gold::before {
          content: '';
          width: 24px;
          height: 2px;
          background: var(--gold);
          border-radius: 2px;
        }

        .section-heading {
          font-family: 'Cormorant Garamond', serif;
          font-size: clamp(2rem, 3.5vw, 2.9rem);
          font-weight: 700;
          color: var(--text);
          line-height: 1.15;
          margin-bottom: 16px;
        }
        .section-heading em { color: var(--sage); font-style: italic; }
        .section-sub {
          font-family: 'Outfit', sans-serif;
          font-size: 1rem;
          color: var(--muted);
          line-height: 1.65;
          max-width: 560px;
        }

        /* ── ABOUT SECTION ─────────────────────────── */
        .about-section {
          background: var(--bg);
          padding: 100px 40px;
        }
        .about-inner {
          max-width: 1200px;
          margin: 0 auto;
          display: grid;
          grid-template-columns: 1fr 1fr;
          gap: 80px;
          align-items: center;
        }
        .about-img-wrap {
          position: relative;
          border-radius: var(--radius);
          overflow: visible;
        }
        .about-img-main {
          width: 100%;
          height: 500px;
          object-fit: cover;
          border-radius: var(--radius);
          box-shadow: var(--shadow-lg);
          display: block;
        }
        .about-img-float {
          position: absolute;
          bottom: -28px;
          right: -28px;
          width: 180px;
          height: 180px;
          border-radius: 18px;
          object-fit: cover;
          border: 4px solid var(--surface);
          box-shadow: var(--shadow);
          animation: floatY 5s ease-in-out infinite;
        }
        .about-badge {
          position: absolute;
          top: 24px;
          left: -20px;
          background: var(--gold);
          color: #fff;
          border-radius: 14px;
          padding: 14px 20px;
          text-align: center;
          box-shadow: 0 6px 24px rgba(184,146,42,0.3);
        }
        .about-badge strong { display: block; font-family: 'Cormorant Garamond', serif; font-size: 1.7rem; font-weight: 700; }
        .about-badge span { font-size: 0.75rem; font-weight: 600; opacity: 0.9; }

        .about-content { padding: 20px 0; }
        .about-features {
          display: grid;
          grid-template-columns: 1fr 1fr;
          gap: 16px;
          margin-top: 32px;
        }
        .about-feat {
          display: flex;
          align-items: flex-start;
          gap: 12px;
          background: var(--ivory);
          border: 1px solid var(--border);
          border-radius: 14px;
          padding: 14px 16px;
        }
        .about-feat-icon { font-size: 1.4rem; flex-shrink: 0; margin-top: 2px; }
        .about-feat-text strong {
          display: block;
          font-family: 'Outfit', sans-serif;
          font-size: 0.88rem;
          font-weight: 600;
          color: var(--text);
          margin-bottom: 3px;
        }
        .about-feat-text span { font-size: 0.78rem; color: var(--muted); }

        /* ── SERVICES SECTION ──────────────────────── */
        .services-section {
          background: var(--bg2);
          padding: 100px 40px;
        }
        .services-inner { max-width: 1200px; margin: 0 auto; }
        .services-header {
          display: flex;
          justify-content: space-between;
          align-items: flex-end;
          margin-bottom: 56px;
          gap: 30px;
          flex-wrap: wrap;
        }
        .services-grid {
          display: grid;
          grid-template-columns: repeat(3, 1fr);
          gap: 28px;
        }
        .service-card {
          background: var(--surface);
          border: 1px solid var(--border);
          border-radius: var(--radius);
          padding: 32px 28px;
          position: relative;
          transition: transform 0.45s cubic-bezier(.34,1.56,.64,1), box-shadow 0.35s ease, border-color 0.3s;
          cursor: default;
        }
        .service-card:hover {
          transform: translateY(-10px);
          box-shadow: 0 20px 56px rgba(61,107,79,0.14);
          border-color: rgba(61,107,79,0.3);
        }
        .service-icon-wrap {
          width: 60px;
          height: 60px;
          background: var(--sage-xs);
          border-radius: 16px;
          display: flex;
          align-items: center;
          justify-content: center;
          font-size: 1.7rem;
          margin-bottom: 20px;
        }
        .service-tag {
          position: absolute;
          top: 24px;
          right: 20px;
          background: var(--sage-xs);
          color: var(--sage);
          border-radius: 50px;
          padding: 4px 12px;
          font-family: 'Outfit', sans-serif;
          font-size: 0.7rem;
          font-weight: 600;
          letter-spacing: 0.04em;
        }
        .service-title {
          font-family: 'Cormorant Garamond', serif;
          font-size: 1.45rem;
          font-weight: 700;
          color: var(--text);
          margin-bottom: 10px;
        }
        .service-desc {
          font-family: 'Outfit', sans-serif;
          font-size: 0.9rem;
          color: var(--muted);
          line-height: 1.65;
        }
        .service-arrow {
          display: inline-flex;
          align-items: center;
          gap: 6px;
          margin-top: 20px;
          font-family: 'Outfit', sans-serif;
          font-size: 0.85rem;
          font-weight: 600;
          color: var(--sage);
          text-decoration: none;
          transition: gap 0.2s;
        }
        .service-arrow:hover { gap: 10px; }

        /* ── VETS SECTION ──────────────────────────── */
        .vets-section {
          background: var(--ivory);
          padding: 100px 40px;
        }
        .vets-inner { max-width: 1200px; margin: 0 auto; }
        .vets-header { text-align: center; margin-bottom: 56px; }
        .vets-header .section-sub { margin: 0 auto; }
        .vets-grid {
          display: grid;
